function.body:
TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Lines RECORD;

    v_User_ID VARCHAR2(32) ;
    v_RecordId VARCHAR2(32);
    v_ResultStr VARCHAR2(2000):='';
    v_isquotation NUMBER;
    v_action VARCHAR2(60);
    v_reason_rejection VARCHAR2(255);

BEGIN

  --  Update AD_PInstance
  DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
  v_ResultStr := 'PInstanceNotFound';
  AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;

  BEGIN --BODY

-- GET:    
    IF (p_PInstance_ID IS NOT NULL) THEN
      --  Update AD_PInstance
      DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
      v_ResultStr:='PInstanceNotFound';
      AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
      -- Get Parameters
      v_ResultStr:='ReadingParameters';
      FOR Cur_Parameter IN
        (SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String,
          p.P_Number, p.P_Date
        FROM AD_PINSTANCE i
        LEFT JOIN AD_PINSTANCE_PARA p
          ON i.AD_PInstance_ID=p.AD_PInstance_ID
        WHERE i.AD_PInstance_ID=p_PInstance_ID
        ORDER BY p.SeqNo
        )
      LOOP
        v_RecordId:=Cur_Parameter.Record_ID;
        v_User_ID:=Cur_Parameter.AD_User_ID;
        IF Cur_Parameter.ParameterName = 'Ssaddis_approve_action' THEN
            v_action := Cur_Parameter.P_String;
        END IF;

        IF Cur_Parameter.ParameterName = 'reason_rejection' THEN
            v_reason_rejection := Cur_Parameter.P_String;
        END IF;
      END LOOP; -- Get Parameter
    ELSE
      v_RecordId:=p_Order_ID;
      SELECT CREATEDBY INTO v_User_ID  FROM C_ORDER  WHERE C_ORDER_ID=p_Order_ID;
    END IF;
    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_RecordId) ; 

	IF v_action = 'A' THEN
		UPDATE c_order SET EM_Sssoin_Generalstatus='CMA', em_sssoin_reason_rejection = v_reason_rejection,
        EM_Sssoin_Creditapp = now(), EM_Sssoin_Creditappby = v_User_ID
        WHERE c_order_id=v_RecordId;
	ELSEIF v_action = 'R' THEN
		UPDATE c_order SET EM_Sssoin_Generalstatus='CMD', em_sssoin_reason_rejection = v_reason_rejection, 
        EM_Sssoin_Creditapp = now(), EM_Sssoin_Creditappby = v_User_ID
        WHERE c_order_id=v_RecordId;
	END IF;

    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 1, '@Success@') ;
    RETURN;


  END; --BODY
  EXCEPTION
  WHEN OTHERS THEN
    v_ResultStr:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
    RETURN;
END SSSOIN_CREDITAPPROVE
